from flask import Flask, jsonify
from pymemcache.client import base
import time

app = Flask(__name__)
memcached_client = base.Client(('localhost', 11211))

# Mock database query function
def get_data_from_database():
    time.sleep(2)  # Simulate a slow database query
    return {'data': 'This is the database result'}

# Decorator for caching
def cache_result(ttl=60):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = func.__name__
            cached_result = memcached_client.get(cache_key)
            if cached_result:
                return jsonify(eval(cached_result))
            result = func(*args, **kwargs)
            memcached_client.set(cache_key, str(result), expire=ttl)
            return jsonify(result)
        return wrapper
    return decorator

@app.route('/data')
@cache_result(ttl=120)
def get_data():
    return get_data_from_database()

@app.route('/api')
@cache_result(ttl=30)
def api_response():
    response = {'message': 'This is an API response', 'timestamp': time.time()}
    return response

if __name__ == '__main__':
    app.run(debug=True)